if (! function_exists('roman_numeral_converter')) {
    function roman_numeral_converter($input, $direction = null)
    {
        $input = trim($input);
        $direction = $direction ?? 'auto';

        // Auto-detect: if contains only digits, it's Arabic going to Roman
        if ($direction === 'auto') {
            $direction = preg_match('/^[0-9]+$/', $input) ? 'to_roman' : 'to_arabic';
        }

        if ($direction === 'to_roman') {
            $num = (int)$input;
            if ($num < 1 || $num > 3999) {
                return json_encode(['error' => 'Number must be between 1 and 3999 for Roman numeral conversion.']);
            }

            $values = [
                1000 => 'M', 900 => 'CM', 500 => 'D', 400 => 'CD',
                100 => 'C', 90 => 'XC', 50 => 'L', 40 => 'XL',
                10 => 'X', 9 => 'IX', 5 => 'V', 4 => 'IV', 1 => 'I'
            ];

            $result = '';
            $remaining = $num;
            foreach ($values as $val => $symbol) {
                while ($remaining >= $val) {
                    $result .= $symbol;
                    $remaining -= $val;
                }
            }

            return json_encode([
                'direction' => 'arabic_to_roman',
                'arabic' => $num,
                'roman' => $result,
            ]);
        } else {
            // Roman → Arabic
            $roman = strtoupper($input);
            if (!preg_match('/^[IVXLCDM]+$/', $roman)) {
                return json_encode(['error' => 'Invalid Roman numeral. Valid characters: I, V, X, L, C, D, M']);
            }

            $values = [
                'I' => 1, 'V' => 5, 'X' => 10, 'L' => 50,
                'C' => 100, 'D' => 500, 'M' => 1000
            ];

            $result = 0;
            $len = strlen($roman);
            for ($i = 0; $i < $len; $i++) {
                $current = $values[$roman[$i]];
                $next = ($i + 1 < $len) ? $values[$roman[$i + 1]] : 0;
                if ($current < $next) {
                    $result -= $current;
                } else {
                    $result += $current;
                }
            }

            return json_encode([
                'direction' => 'roman_to_arabic',
                'roman' => $roman,
                'arabic' => $result,
            ]);
        }
    }
